function springCalc(params) {
  const { d, D, Na, P, mat: matKey, preset = false, Lf = null } = params;

  const result = {
    error: null,
    d, D, Na, P, mat: matKey,
    G: null, sigmaB: null,
    C: null, K: null, k: null, delta: null, tau: null,
    ratio: null, Lc: null, Do: null, Di: null, Nt: null,
    preset: false, tauLimit: 0.45,
    Lf: null, deltaMax: null, P_solid: null, bottomOut: false, lambda: null,
    stressOK: false, cRange: false, isSafe: false,
    status: 'NG_STRESS',
    warnings: [],
  };

  // バリデーション
  const material = SPRING_MATERIALS[matKey];
  if (!material) {
    result.error = `材料データが見つかりません: ${matKey}`;
    return result;
  }
  if (isNaN(d) || d <= 0)  { result.error = '線径 d が無効です'; return result; }
  if (isNaN(D) || D <= 0)  { result.error = '中心径 D が無効です'; return result; }
  if (isNaN(Na) || Na <= 0){ result.error = '有効巻数 Na が無効です'; return result; }
  if (isNaN(P) || P < 0)   { result.error = '荷重 P が無効です'; return result; }

  const G      = material.G;
  const sigmaB = springGetSigmaB(matKey, d);
  const C      = D / d;

  if (C < 2) {
    result.error = `ばね指数 C = ${C.toFixed(2)} < 2（線径が大きすぎます）`;
    return result;
  }

  // JIS B 2704 計算式
  const K     = (4 * C - 1) / (4 * C - 4) + 0.615 / C;
  const k     = G * Math.pow(d, 4) / (8 * Math.pow(D, 3) * Na);
  const delta = k > 0 ? P / k : 0;
  const tau   = 8 * P * D * K / (Math.PI * Math.pow(d, 3));
  const ratio = tau / sigmaB;
  const Lc    = (Na + 2) * d;
  const Do    = D + d;
  const Di    = D - d;
  const Nt    = Na + 2;

  // 許容応力比（JIS B 2704 プリセット区分）
  const tauLimit = preset ? 0.56 : 0.45;
  const stressOK = ratio <= tauLimit;
  const cRange   = C >= 4 && C <= 14;

  // 底付き・座屈確認（Lf 指定時）
  let deltaMax = null, P_solid = null, bottomOut = false, lambda = null;
  const lfWarnings = [];
  const lfVal = (Lf !== null && Lf !== '' && !isNaN(Number(Lf))) ? Number(Lf) : null;
  if (lfVal !== null && lfVal > 0) {
    if (lfVal <= Lc) {
      result.error = `自由長 Lf = ${lfVal} mm が密着高さ Lc = ${Lc.toFixed(2)} mm 以下です`;
      return result;
    }
    deltaMax  = lfVal - Lc;
    P_solid   = k * deltaMax;
    bottomOut = P >= P_solid;
    lambda    = lfVal / D;
    if (bottomOut) {
      lfWarnings.push(`底付き: P=${P}N が密着荷重 P_solid=${P_solid.toFixed(1)}N 以上です。荷重を下げるか Lf を増やしてください。`);
    } else if (P > 0.8 * P_solid) {
      lfWarnings.push(`底付き接近: P は密着荷重の${(P / P_solid * 100).toFixed(0)}%です（P_solid=${P_solid.toFixed(1)}N）。`);
    }
    if (lambda > 4) {
      lfWarnings.push(`座屈注意: Lf/D = ${lambda.toFixed(2)} > 4。座屈ガイドの使用を検討してください。`);
    }
  }

  const isSafe = stressOK && cRange && !bottomOut;

  let status;
  if (!stressOK)        status = 'NG_STRESS';
  else if (!cRange)     status = 'NG_CRANGE';
  else if (bottomOut)   status = 'NG_BOTTOM';
  else                  status = 'OK';

  // 警告メッセージ
  const warnings = [];
  if (!stressOK)
    warnings.push(`応力超過: τ/σB = ${ratio.toFixed(4)} > ${tauLimit}。線径を太くするかコイル径を大きくしてください。`);
  if (C < 4)
    warnings.push(`ばね指数 C = ${C.toFixed(2)} < 4（推奨範囲）。コイル径を大きくするか線径を細くしてください。`);
  if (C > 14)
    warnings.push(`ばね指数 C = ${C.toFixed(2)} > 14（推奨範囲）。座屈リスクが増加します。`);
  warnings.push(...lfWarnings);

  return Object.assign(result, {
    G, sigmaB,
    C, K, k, delta, tau, ratio, Lc, Do, Di, Nt,
    preset, tauLimit,
    Lf: lfVal, deltaMax, P_solid, bottomOut, lambda,
    stressOK, cRange, isSafe, status, warnings,
  });
}

const Spring = {
  /** 対応材料一覧 */
  MATERIALS: SPRING_MATERIALS,

  /**
   * JIS最小引張強さ σB を取得する。
   * @param {string} matKey
   * @param {number} d
   * @returns {number}
   */
  getSigmaB: springGetSigmaB,

  /**
   * コイルばね計算（JIS B 2704）。
   * @param {object} params - { d, D, Na, P, mat }
   * @returns {SpringResult}
   */
  calc: springCalc,

