/**
 * verify-spring-jis.js
 * JIS B 2704 コイルばね計算 数値検証テスト
 * mechsense-core.js v1.4.0 Spring モジュール
 *
 * 実行: node verify-spring-jis.js
 */

'use strict';

const MechSense = require('./mechsense-core.js');
const Spring = MechSense.Spring;

let pass = 0, fail = 0;

// ─── ヘルパー ────────────────────────────────────────

function near(actual, expected, tol = 0.01) {
  return Math.abs(actual - expected) <= tol;
}

function nearPct(actual, expected, pctTol = 0.1) {
  // 期待値に対する相対誤差 % ≤ pctTol %
  if (expected === 0) return actual === 0;
  return Math.abs((actual - expected) / expected * 100) <= pctTol;
}

function check(label, actual, expected, tol = 0.01) {
  const ok = near(actual, expected, tol);
  const icon = ok ? '✅' : '❌';
  if (ok) pass++; else fail++;
  if (!ok) {
    console.log(`  ${icon} ${label}: 期待=${expected.toFixed(6)}, 実際=${actual.toFixed(6)}, 差=${(actual - expected).toFixed(6)}`);
  } else {
    console.log(`  ${icon} ${label}: ${actual.toFixed(4)} (期待 ${expected.toFixed(4)})`);
  }
}

function checkEq(label, actual, expected) {
  const ok = actual === expected;
  const icon = ok ? '✅' : '❌';
  if (ok) pass++; else fail++;
  console.log(`  ${icon} ${label}: ${JSON.stringify(actual)} (期待 ${JSON.stringify(expected)})`);
}

function checkTrue(label, actual) {
  const ok = actual === true;
  if (ok) pass++; else fail++;
  console.log(`  ${ok ? '✅' : '❌'} ${label}: ${actual}`);
}

function checkFalse(label, actual) {
  const ok = actual === false;
  if (ok) pass++; else fail++;
  console.log(`  ${ok ? '✅' : '❌'} ${label}: ${actual}`);
}

function checkNull(label, actual) {
  const ok = actual === null;
  if (ok) pass++; else fail++;
  console.log(`  ${ok ? '✅' : '❌'} ${label}: ${actual}`);
}

function checkNoError(r) {
  const ok = r.error === null;
  if (ok) pass++; else fail++;
  if (!ok) console.log(`  ❌ エラーあり: ${r.error}`);
}

// ─── 手動計算式（テスト設計根拠） ─────────────────────

// C = D/d
// K = (4C-1)/(4C-4) + 0.615/C
// k = G*d^4 / (8*D^3*Na)
// δ = P/k
// τ = 8*P*D*K / (π*d^3)
// ratio = τ/σB
// Lc = (Na+2)*d
// Do = D+d, Di = D-d, Nt = Na+2
// tauLimit = preset ? 0.56 : 0.45

// ═══════════════════════════════════════════════════════
console.log('\n═══════════════════════════════════════════════════════');
console.log('  JIS B 2704 コイルばね計算 数値検証テスト (mechsense v1.4.0)');
console.log('═══════════════════════════════════════════════════════\n');

// ───────────────────────────────────────────────────────
// TC-01: 基本計算検証（SW-B, 正常系）
// 目的: 全計算値を手動計算結果と照合する最重要テスト
// 材料: SW-B, d=3.0mm, D=20mm, Na=8, P=100N
// σB: d=3.0 → テーブル d≤3.2 → 1370 MPa
// C  = 20/3 = 6.6667
// K  = (26.6667-1)/(26.6667-4) + 0.615/6.6667 = 25.6667/22.6667 + 0.09225 = 1.22460
// k  = 78500×81/(512000) = 12.4189 N/mm
// δ  = 100/12.4189 = 8.0522 mm
// τ  = 8×100×20×1.22460/(π×27) = 19593.6/84.823 = 231.00 MPa
// ratio = 231.00/1370 = 0.16861
// ───────────────────────────────────────────────────────
console.log('── TC-01: 基本計算検証（SW-B, status=OK）────────────');
{
  const r = Spring.calc({ d: 3.0, D: 20.0, Na: 8, P: 100, mat: 'SW-B' });
  checkNoError(r);
  check('σB',    r.sigmaB,  1370,     0.5);
  check('C',     r.C,       20/3,     0.0001);
  check('K',     r.K,       1.22460,  0.0001);
  check('k',     r.k,       12.4189,  0.001);
  check('δ',     r.delta,   8.0522,   0.001);
  check('τ',     r.tau,     231.00,   0.05);
  check('ratio', r.ratio,   0.16861,  0.0001);
  check('Lc',    r.Lc,      30.0,     0.01);
  check('Do',    r.Do,      23.0,     0.01);
  check('Di',    r.Di,      17.0,     0.01);
  check('Nt',    r.Nt,      10,       0.01);
  checkEq('status',    r.status,   'OK');
  checkTrue('stressOK',  r.stressOK);
