// k  = 78500×1.2^4/(8×10^3×6) = 78500×2.0736/480000 = 3.3912 N/mm
// τ  = 8×300×10×1.17603/(π×1.2^3) = 28225/5.4288 = 5199.1 MPa
// ratio = 5199.1/1910 = 2.7220 >> 0.45 → NG_STRESS
// ───────────────────────────────────────────────────────
console.log('\n── TC-02: NG_STRESS 検証（SW-C）────────────────────');
{
  const r = Spring.calc({ d: 1.2, D: 10.0, Na: 6, P: 300, mat: 'SW-C' });
  checkNoError(r);
