// ───────────────────────────────────────────────────────
// TC-07: 底付き接近警告（P > 0.8×P_solid, 底付きなし）
// 材料: SW-B, d=3.0mm, D=20mm, Na=8, P=50N, Lf=34mm
// Lc=30mm, deltaMax=4mm, P_solid=12.4189×4=49.68N
// P=50N > P_solid=49.68N → bottomOut=true（やや届く）
// → Lf=36mmで試すと: deltaMax=6mm, P_solid=74.5N, P=50 < 74.5 → 接近確認
// 0.8×74.5=59.6N > P=50N... 50/74.5=67% < 80% → 接近警告なし
// Lf=33mm: deltaMax=3mm, P_solid=37.3N, P=50>37.3 → NG_BOTTOM
// ── わかりやすいケース: P=55N, Lf=36mm
// P_solid=12.4189×6=74.5N, P=55N
// 55/74.5=73.8% < 80% → 接近警告なし（つまり接近なし）
// P=62N, Lf=36mm: 62/74.5=83.2% → 接近警告あり ✅
// ───────────────────────────────────────────────────────
console.log('\n── TC-07: 底付き接近警告（P~83%×P_solid）───────────');
{
  const r = Spring.calc({ d: 3.0, D: 20.0, Na: 8, P: 62, mat: 'SW-B', Lf: 36 });
  checkNoError(r);
  const expectedPsolid = 12.4189 * 6; // ~74.5N
  check('P_solid', r.P_solid, expectedPsolid, 0.5);
  checkFalse('bottomOut', r.bottomOut);  // 62 < 74.5 → 底付きなし
  checkEq('status', r.status, 'OK');
  checkTrue('isSafe', r.isSafe);
  // 接近警告が warnings に含まれるか確認
  const hasNearWarning = r.warnings.some(w => w.includes('底付き接近'));
  const ok = hasNearWarning === true;
  if (ok) pass++; else fail++;
  console.log(`  ${ok ? '✅' : '❌'} 底付き接近警告あり: ${hasNearWarning}`);
}

